import 'package:firebase_auth/firebase_auth.dart'; import 'package:google_sign_in/google_sign_in.dart'; import 'package:injectable/injectable.dart'; import '../../../core/constants/app_constants.dart'; import '../../../core/utils/app_logger.dart'; @singleton class GoogleSignInService { Future<UserCredential?> signIn() async { try { final acc = await GoogleSignIn(clientId: AppConstants.firebaseWebApiKey).signIn(); if (acc == null) return null; final auth = await acc.authentication; final cred = GoogleAuthProvider.credential(accessToken: auth.accessToken, idToken: auth.idToken); return await FirebaseAuth.instance.signInWithCredential(cred); } catch (e) { AppLogger.error('Google sign in failed', e); return null; } } Future<void> signOut() => GoogleSignIn().signOut(); }